#!/usr/bin/env python3
"""
PPT Master - Layout Reference Bridge

Convert layout_reference.json and content_mapping.json into a Strategist-readable
layout_reference_brief.md. For lightweight slide-image rebuilds, it can also
write a compact design_spec.md directly from the same artifacts.

Usage:
    python3 scripts/layout_reference_to_design_spec.py <project_path> [--output layout_reference_brief.md]
    python3 scripts/layout_reference_to_design_spec.py <project_path> --write-design-spec

Examples:
    python3 scripts/layout_reference_to_design_spec.py projects/demo

Dependencies:
    None (only uses standard library)
"""

from __future__ import annotations

import argparse
import json
from pathlib import Path
from typing import Any


def load_json(path: Path) -> dict[str, Any]:
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except FileNotFoundError as exc:
        raise SystemExit(f"File not found: {path}") from exc
    except json.JSONDecodeError as exc:
        raise SystemExit(f"Invalid JSON in {path}: {exc}") from exc


def _as_lines(value: Any) -> list[str]:
    if isinstance(value, list):
        return [str(item).strip() for item in value if str(item).strip()]
    if isinstance(value, str) and value.strip():
        return [value.strip()]
    return []


def _string_values(value: Any) -> list[str]:
    if isinstance(value, str):
        return [value]
    if isinstance(value, list):
        out: list[str] = []
        for item in value:
            out.extend(_string_values(item))
        return out
    if isinstance(value, dict):
        out = []
        for item in value.values():
            out.extend(_string_values(item))
        return out
    return []


def _dense_signals(layout: dict[str, Any], renderable: dict[str, Any]) -> dict[str, int | bool]:
    modules = renderable.get("modules", [])
    item_count = 0
    if isinstance(modules, list):
        for module in modules:
            if not isinstance(module, dict):
                continue
            for key in ["items", "body", "result"]:
                value = module.get(key)
                if isinstance(value, list):
                    item_count += len(value)
                elif isinstance(value, str) and value.strip():
                    item_count += 1
    zone_count = len([zone for zone in layout.get("zones", []) if isinstance(zone, dict)])
    text_chars = sum(len(text) for text in _string_values(renderable))
    explicit = layout.get("dense_rebuild_mode", {})
    enabled = bool(isinstance(explicit, dict) and explicit.get("enabled")) or zone_count >= 8 or item_count >= 20 or text_chars >= 900
    return {
        "enabled": enabled,
        "zone_count": zone_count,
        "module_item_count": item_count,
        "renderable_text_chars": text_chars,
    }


def _table_row(values: list[Any]) -> str:
    return "| " + " | ".join(str(value).replace("\n", " ").strip() for value in values) + " |"


def build_brief(layout: dict[str, Any], mapping: dict[str, Any]) -> str:
    source = layout.get("source_reference", {})
    canvas = layout.get("canvas", {})
    style = layout.get("style_reference", {})
    chain = layout.get("main_chain", {})
    renderable = mapping.get("renderable_content", {})
    density = _dense_signals(layout, renderable)

    lines: list[str] = [
        "# Layout Reference Brief",
        "",
        "> Generated by `layout_reference_to_design_spec.py`. Use this as source input for Strategist; `design_spec.md` and `spec_lock.md` remain authoritative after Step 4.",
        "",
        "## Source Trust",
        "",
        _table_row(["Field", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Purpose", source.get("purpose", "")]),
        _table_row(["Content trust", source.get("content_trust", "")]),
        _table_row(["Copy text from reference", source.get("copy_text_from_reference", False)]),
        "",
        "## Layout Contract",
        "",
        _table_row(["Field", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Canvas", f"{canvas.get('aspect', '')} {canvas.get('width_px', '')}x{canvas.get('height_px', '')}"]),
        _table_row(["Page role", layout.get("page_role", "")]),
        _table_row(["Layout type", layout.get("layout_type", "")]),
        _table_row(["Main message slot", layout.get("main_message_slot", "title_area")]),
        _table_row(["Chain direction", chain.get("direction", "")]),
        _table_row(["Relationship style", chain.get("relationship_style", "")]),
        _table_row(["Support layer", chain.get("support_layer", "")]),
        "",
        "## Style Cues",
        "",
        _table_row(["Cue", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Tone", style.get("tone", "")]),
        _table_row(["Primary", style.get("primary_color", "")]),
        _table_row(["Accent", style.get("accent_color", "")]),
        _table_row(["Background", style.get("background", "")]),
        _table_row(["Card style", style.get("card_style", "")]),
        _table_row(["Line style", style.get("line_style", "")]),
        _table_row(["Font", style.get("font_family", "")]),
        _table_row(["Density", style.get("density", "")]),
        _table_row(["Dense rebuild mode", density.get("enabled")]),
        _table_row(["Dense signals", f"zones={density.get('zone_count')}, items={density.get('module_item_count')}, chars={density.get('renderable_text_chars')}"]),
        "",
        "## Zones",
        "",
        _table_row(["Zone", "Role", "Position", "Ratio box", "Contains", "Weight"]),
        _table_row(["---", "---", "---", "---", "---", "---"]),
    ]

    for zone in layout.get("zones", []):
        if not isinstance(zone, dict):
            continue
        ratio_box = ",".join(
            str(zone.get(key, ""))
            for key in ["x_ratio", "y_ratio", "w_ratio", "h_ratio"]
        )
        contains = ", ".join(_as_lines(zone.get("contains", [])))
        lines.append(_table_row([
            zone.get("id", ""),
            zone.get("role", ""),
            zone.get("position_hint", ""),
            ratio_box,
            contains,
            zone.get("visual_weight", ""),
        ]))

    lines.extend([
        "",
        "## Renderable Content",
        "",
        _table_row(["Field", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Title", renderable.get("title", "")]),
        _table_row(["Subtitle", renderable.get("subtitle", "")]),
        _table_row(["Core judgment", renderable.get("core_judgment", "")]),
        _table_row(["Main chain labels", " / ".join(_as_lines(renderable.get("main_chain_labels", [])))]),
        "",
        "## Modules",
        "",
        _table_row(["Zone", "Title", "Body"]),
        _table_row(["---", "---", "---"]),
    ])

    for module in renderable.get("modules", []):
        if not isinstance(module, dict):
            continue
        body = "；".join(_as_lines(module.get("body", [])))
        lines.append(_table_row([module.get("zone_id", ""), module.get("title", ""), body]))

    overflow = mapping.get("content_overflow", [])
    notes = mapping.get("terminology_notes", [])
    lines.extend([
        "",
        "## Planning Notes",
        "",
        _table_row(["Item", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Content overflow", "；".join(_as_lines(overflow))]),
        _table_row(["Terminology notes", "；".join(_as_lines(notes))]),
        "",
        "## Strategist Instructions",
        "",
        "- Use this brief to inform `design_spec.md` §V Layout and §IX Content Outline.",
        "- Keep final visible text limited to `renderable_content`.",
        "- Do not copy unconfirmed text from the reference image.",
        "- Rebuild the page with editable SVG/PPT elements; do not flatten the full reference image.",
        "- Assign `page_rhythm` in `spec_lock.md`; use `dense` for information-heavy zone layouts unless the content calls for `anchor` or `breathing`.",
        "- If Dense rebuild mode is true, prioritize readable/editable text, shorten line breaks before reducing line height, and simplify repeated micro-icons.",
        "",
    ])
    return "\n".join(lines)


def _first_non_empty(*values: Any) -> str:
    for value in values:
        if isinstance(value, str) and value.strip():
            return value.strip()
    return ""


def build_design_spec(layout: dict[str, Any], mapping: dict[str, Any]) -> str:
    source = layout.get("source_reference", {})
    canvas = layout.get("canvas", {})
    style = layout.get("style_reference", {})
    renderable = mapping.get("renderable_content", {})
    title = _first_non_empty(renderable.get("title"), layout.get("layout_type"), "Slide Image Rebuild")
    primary = _first_non_empty(style.get("primary_color"), "#003B85")
    accent = _first_non_empty(style.get("accent_color"), "#D71920")
    background = _first_non_empty(style.get("background"), "#FFFFFF")
    font = _first_non_empty(style.get("font_family"), "Microsoft YaHei")
    density = _first_non_empty(style.get("density"), "reference")
    tone = _first_non_empty(style.get("tone"), "formal_business")
    native = layout.get("editability_policy", {}).get("native_editable", [])
    image_allowed = layout.get("editability_policy", {}).get("image_allowed", [])

    zone_rows = [
        _table_row(["Zone", "Role", "Component", "Position", "Ratio box"]),
        _table_row(["---", "---", "---", "---", "---"]),
    ]
    for zone in layout.get("zones", []):
        if not isinstance(zone, dict):
            continue
        ratio_box = ",".join(str(zone.get(key, "")) for key in ["x_ratio", "y_ratio", "w_ratio", "h_ratio"])
        zone_rows.append(_table_row([
            zone.get("id", ""),
            zone.get("role", ""),
            zone.get("component", ""),
            zone.get("position_hint", ""),
            ratio_box,
        ]))

    module_rows = [
        _table_row(["Zone", "Title", "Body", "Result"]),
        _table_row(["---", "---", "---", "---"]),
    ]
    for module in renderable.get("modules", []):
        if not isinstance(module, dict):
            continue
        module_rows.append(_table_row([
            module.get("zone_id", ""),
            module.get("title", ""),
            "；".join(_as_lines(module.get("body", []))),
            "；".join(_as_lines(module.get("result", []))),
        ]))

    lines = [
        "---",
        "kind: project_design_spec",
        "workflow: slide-image-rebuild",
        "---",
        "",
        "# Design Spec",
        "",
        "## Template Overview",
        "",
        f"Rebuild `{title}` as a native editable PPT slide from the supplied reference image. Use the reference for layout and visual fidelity; final visible text must come from `content_mapping.json`.",
        "",
        "## Canvas",
        "",
        _table_row(["Field", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Format", canvas.get("aspect", "16:9")]),
        _table_row(["Width", canvas.get("width_px", 1280)]),
        _table_row(["Height", canvas.get("height_px", 720)]),
        _table_row(["Safe margin", canvas.get("safe_margin_px", "")]),
        "",
        "## Color Scheme",
        "",
        _table_row(["Token", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Background", background]),
        _table_row(["Primary", primary]),
        _table_row(["Accent", accent]),
        _table_row(["Border", _first_non_empty(style.get("line_color"), style.get("border"), "#2F6EC4")]),
        _table_row(["Text", "#111827"]),
        "",
        "## Typography",
        "",
        _table_row(["Token", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Font family", font]),
        _table_row(["Tone", tone]),
        _table_row(["Density", density]),
        "",
        "## Page Structure",
        "",
        *zone_rows,
        "",
        "## Content Outline",
        "",
        _table_row(["Field", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Title", renderable.get("title", "")]),
        _table_row(["Intro", renderable.get("intro", "")]),
        _table_row(["Takeaway", renderable.get("takeaway", "")]),
        "",
        *module_rows,
        "",
        "## Icon Style",
        "",
        "- Use editable semantic vector icons for functional icons.",
        "- Keep page numbers, decorative badges, and chrome labels outside `icon_reconstruction.icons[]` unless they carry semantic icon meaning.",
        "- Add `data-icon-id` only for icons declared in `layout_reference.json`.",
        "",
        "## Editability",
        "",
        _table_row(["Policy", "Value"]),
        _table_row(["---", "---"]),
        _table_row(["Native editable", ", ".join(_as_lines(native))]),
        _table_row(["Image allowed", ", ".join(_as_lines(image_allowed))]),
        _table_row(["Never flatten full slide", layout.get("editability_policy", {}).get("never_flatten_full_slide", True)]),
        _table_row(["Reference text trust", source.get("content_trust", "")]),
        "",
    ]
    return "\n".join(lines)


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Generate layout_reference_brief.md for Strategist.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
    )
    parser.add_argument("project_path", type=Path, help="Project directory")
    parser.add_argument("--output", type=Path, help="Output path; defaults to <project_path>/layout_reference_brief.md")
    parser.add_argument(
        "--write-design-spec",
        action="store_true",
        help="Also write <project_path>/design_spec.md from layout/content artifacts.",
    )
    parser.add_argument(
        "--design-spec-output",
        type=Path,
        help="Design spec output path; defaults to <project_path>/design_spec.md when --write-design-spec is set.",
    )
    return parser


def main(argv: list[str] | None = None) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)
    project_path = args.project_path
    layout = load_json(project_path / "layout_reference.json")
    mapping = load_json(project_path / "content_mapping.json")
    output = args.output or project_path / "layout_reference_brief.md"
    output.write_text(build_brief(layout, mapping), encoding="utf-8")
    print(f"Wrote {output}")
    if args.write_design_spec:
        design_spec_output = args.design_spec_output or project_path / "design_spec.md"
        design_spec_output.write_text(build_design_spec(layout, mapping), encoding="utf-8")
        print(f"Wrote {design_spec_output}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
